// 1. Sadə Generic Funksiya
function identity<T>(value: T): T {
  return value;
}
const num = identity<number>(42); // T = number
console.log(num); // Çıxış: 42
const str = identity<string>("Hello"); // T = string
console.log(str); // Çıxış: Hello

// 2. Generic ilə massiv funksiyası
function getFirst<T>(arr: T[]): T {
  return arr[0];
}
const firstNum = getFirst<number>([1, 2, 3]); // T = number
console.log(firstNum); // Çıxış: 1
const firstStr = getFirst<string>(["a", "b", "c"]); // T = string
console.log(firstStr); // Çıxış: a

// 3. Generic ilə məhdudiyyətlər
function printLength<T extends { length: number }>(item: T): number {
  return item.length;
}
console.log(printLength<string>("Test")); // Çıxış: 4
console.log(printLength<string[]>(["a", "b"])); // Çıxış: 2
// console.log(printLength<number>(42)); // Səhv: number-ın length xüsusiyyəti yoxdur

// 4. Çoxsaylı Generic tiplər
function pair<T, U>(first: T, second: U): [T, U] {
  return [first, second];
}
const myPair = pair<string, number>("Age", 25);
console.log(myPair); // Çıxış: ["Age", 25]

// 5. Default Generic tiplər
function wrap<T = string>(value: T): { value: T } {
  return { value };
}
const wrappedString = wrap("Test"); // T avtomatik string olur
const wrappedNumber = wrap<number>(42);
console.log(wrappedString); // Çıxış: { value: "Test" }
console.log(wrappedNumber); // Çıxış: { value: 42 }

// 6. Generic ilə union tipləri
type AllowedType = string | number;
function restrict<T extends AllowedType>(value: T): T {
  return value;
}
console.log(restrict("Hello")); // Çıxış: Hello
console.log(restrict(123)); // Çıxış: 123
// console.log(restrict(true)); // Səhv: boolean AllowedType-a uyğun deyil

// 7. Generic ilə funksiya overload-ları
function processValue<T extends string | number>(value: T): T;
function processValue(value: boolean): string;
function processValue<T>(value: T): T | string {
  if (typeof value === "boolean") {
    return value ? "True" : "False";
  }
  return value;
}
console.log(processValue<string>("Test")); // Çıxış: Test
console.log(processValue<number>(123)); // Çıxış: 123
console.log(processValue(true)); // Çıxış: True

// Sadə mağaza sistemi
interface Product<T> {
  id: string;
  data: T;
}
function createProduct<T>(id: string, data: T): Product<T> {
  return { id, data };
}
const laptop = createProduct<string>("P001", "Laptop");
console.log(laptop); // Çıxış: { id: "P001", data: "Laptop" }
const price = createProduct<number>("P002", 999);
console.log(price); // Çıxış: { id: "P002", data: 999 }

// Generic funksiya ilə məhsul yoxlaması
function checkProduct<T>(product: Product<T>): string {
  return `Product ID: ${product.id}, Data: ${product.data}`;
}
console.log(checkProduct(laptop)); // Çıxış: Product ID: P001, Data: Laptop

// Generic ilə məhdudiyyətli funksiya
function filterByData<T extends string | number>(products: Product<T>[], value: T): Product<T>[] {
  return products.filter(p => p.data === value);
}
const products: Product<string>[] = [laptop, createProduct("P003", "Mouse")];
console.log(filterByData(products, "Laptop")); // Çıxış: [{ id: "P001", data: "Laptop" }]

